/** Phase-1 loading screen. Cycles through scripted status lines so the user
 *  has a sense of forward motion instead of staring at a static spinner for
 *  ~15s while the multi-agent pipeline runs. The pacing is decoupled from the
 *  actual backend progress (we don't get progress events) — it's an *honest*
 *  list of stages the agent goes through, just timed to look right. */
function PreparingScreen({
  listingUrl,
  onCancel,
}: {
  listingUrl: string
  onCancel: () => void
}) {
  const STAGES = [
    "Reading the listing…",
    "Watching the photos…",
    "Parsing the reviews…",
    "Finding your guest…",
    "Drafting the storyboard…",
  ] as const
  const [stage, setStage] = useState(0)

  useEffect(() => {
    const interval = window.setInterval(() => {
      setStage((s) => (s + 1 < STAGES.length ? s + 1 : s))
    }, 3500)
    return () => window.clearInterval(interval)
  }, [STAGES.length])

  return (
    <main className="mx-auto flex w-full max-w-2xl flex-1 flex-col items-center justify-center gap-8 px-6 py-16">
      <div className="flex flex-col items-center gap-2 text-center">
        <p className="text-label text-muted-foreground">Phase 1</p>
        <h2 className="text-display-lg">Building your storyboard.</h2>
        <p className="text-body text-muted-foreground">
          Multi-agent pipeline in motion. Usually 10–20 seconds.
        </p>
      </div>

      <Card className="w-full max-w-lg p-6">
        <ul className="flex flex-col gap-3">
          {STAGES.map((label, i) => {
            const done = i < stage
            const active = i === stage
            return (
              <li key={label} className="flex items-center gap-3">
                <span
                  className={
                    "inline-flex h-5 w-5 shrink-0 items-center justify-center rounded-full border " +
                    (done
                      ? "border-primary bg-primary text-primary-foreground"
                      : active
                        ? "border-primary text-primary"
                        : "border-border text-muted-foreground")
                  }
                  aria-hidden
                >
                  {done ? (
                    <svg viewBox="0 0 12 12" className="h-3 w-3 fill-current">
                      <path d="M10.28 3.22a.75.75 0 0 1 0 1.06l-4.5 4.5a.75.75 0 0 1-1.06 0L2.22 6.28a.75.75 0 1 1 1.06-1.06l1.97 1.97 3.97-3.97a.75.75 0 0 1 1.06 0z" />
                    </svg>
                  ) : active ? (
                    <span className="h-1.5 w-1.5 animate-pulse rounded-full bg-primary" />
                  ) : null}
                </span>
                <span
                  className={
                    "text-body-sm " +
                    (done
                      ? "text-foreground"
                      : active
                        ? "text-foreground"
                        : "text-muted-foreground")
                  }
                >
                  {label}
                </span>
              </li>
            )
          })}
        </ul>
        <p className="mt-5 truncate border-t border-border pt-4 text-body-sm text-muted-foreground">
          <span className="text-foreground">Listing:</span> {listingUrl}
        </p>
      </Card>

      <Button onClick={onCancel} variant="link">
        Cancel
      </Button>
    </main>
  )
}

// src/components/RationaleRail.tsx
import { ChipGroup } from "@/components/ChipGroup"
import { Badge } from "@/components/ui/badge"
import { Card } from "@/components/ui/card"
import { Separator } from "@/components/ui/separator"
import type { AgentDecision } from "../types"

interface RationaleRailProps {
  decision: AgentDecision
}

const SECTIONS: { label: string; key: "hook" | "pacing" | "angle" | "background" }[] = [
  { label: "Hook", key: "hook" },
  { label: "Pacing", key: "pacing" },
  { label: "Angle", key: "angle" },
  { label: "Background", key: "background" },
]

function parseVibes(vibes: string): string[] {
  return vibes
    .split("·")
    .map((v) => v.trim())
    .filter(Boolean)
}

export function RationaleRail({ decision }: RationaleRailProps) {
  const tags = parseVibes(decision.vibes)
  const hasAgentInsights =
    decision.icp ||
    decision.visual_system ||
    decision.reviews_evaluation ||
    decision.photo_analysis
  const hasJudge = typeof decision.judge_score === "number"

  return (
    <aside className="flex w-full max-w-sm shrink-0 flex-col gap-4">
      {tags.length > 0 && (
        <Card className="p-5">
          <p className="text-label text-secondary mb-3">Vibes</p>
          <ChipGroup tags={tags} />
        </Card>
      )}

      {SECTIONS.map(({ label, key }) => (
        <Card key={key} className="p-5">
          <p className="text-label text-secondary mb-3">{label}</p>
          <p className="text-rationale">{String(decision[key])}</p>
        </Card>
      ))}

      {decision.beliefs_applied && decision.beliefs_applied.length > 0 && (
        <Card className="p-5">
          <p className="text-label text-secondary mb-3">Beliefs Applied</p>
          <div className="flex flex-wrap gap-1.5">
            {decision.beliefs_applied.map((belief) => (
              <Badge key={belief} variant="secondary">
                {belief.replace(/_/g, " ")}
              </Badge>
            ))}
          </div>
        </Card>
      )}

      {hasJudge && (
        <Card className="p-5">
          <details>
            <summary className="text-label text-secondary cursor-pointer list-none">
              Editorial Judge ·{" "}
              <span className="font-semibold text-foreground">
                {decision.judge_score?.toFixed(1)}/10
              </span>
            </summary>
            <Separator className="my-3" />
            {decision.judge_rationale && (
              <p className="text-body-sm text-muted-foreground leading-relaxed">
                {decision.judge_rationale}
              </p>
            )}
            {decision.judge_scores_per_brief &&
              decision.judge_scores_per_brief.length > 0 && (
                <div className="mt-3 flex flex-col gap-2">
                  {decision.judge_scores_per_brief.map((s) => (
                    <div
                      key={s.index}
                      className="text-body-sm text-muted-foreground"
                    >
                      <span className="font-medium text-foreground">
                        Brief {s.index}
                      </span>
                      {typeof s.aggregate === "number" && (
                        <> · agg {s.aggregate.toFixed(1)}</>
                      )}
                      {s.weakness && (
                        <span className="block italic">{s.weakness}</span>
                      )}
                    </div>
                  ))}
                </div>
              )}
          </details>
        </Card>
      )}

      {hasAgentInsights && (
        <Card className="p-5">
          <details>
            <summary className="text-label text-secondary cursor-pointer list-none">
              Agent Insights
            </summary>
            <Separator className="my-3" />
            <div className="flex flex-col gap-4">
              {decision.icp?.best_icp?.persona && (
                <div className="flex flex-col gap-1">
                  <p className="text-label text-secondary">ICP</p>
                  <p className="text-rationale">
                    <span className="font-semibold">
                      {decision.icp.best_icp.persona}
                    </span>
                    {typeof decision.icp.best_icp.fit_score === "number" && (
                      <span className="text-muted-foreground">
                        {" · fit "}
                        {decision.icp.best_icp.fit_score.toFixed(2)}
                      </span>
                    )}
                  </p>
                  {decision.icp.best_icp.booking_trigger && (
                    <p className="text-body-sm text-muted-foreground">
                      Trigger: {decision.icp.best_icp.booking_trigger}
                    </p>
                  )}
                </div>
              )}
              {decision.visual_system?.inferred_setting && (
                <div className="flex flex-col gap-1">
                  <p className="text-label text-secondary">Visual System</p>
                  <p className="text-rationale">
                    Setting:{" "}
                    <span className="font-semibold">
                      {decision.visual_system.inferred_setting}
                    </span>
                  </p>
                  {decision.visual_system.music && (
                    <p className="text-body-sm text-muted-foreground">
                      Music: {decision.visual_system.music}
                    </p>
                  )}
                  {decision.visual_system.transitions && (
                    <p className="text-body-sm text-muted-foreground">
                      Transitions: {decision.visual_system.transitions}
                    </p>
                  )}
                </div>
              )}
              {decision.reviews_evaluation?.best_video_quotes?.[0]?.quote && (
                <div className="flex flex-col gap-1">
                  <p className="text-label text-secondary">Review Proof</p>
                  <p className="text-rationale italic">
                    “{decision.reviews_evaluation.best_video_quotes[0].quote}”
                  </p>
                </div>
              )}
              {decision.photo_analysis?.analysis_summary?.one_line_strategy && (
                <div className="flex flex-col gap-1">
                  <p className="text-label text-secondary">Photo Strategy</p>
                  <p className="text-rationale">
                    {decision.photo_analysis.analysis_summary.one_line_strategy}
                  </p>
                </div>
              )}
            </div>
          </details>
        </Card>
      )}

      <Card className="p-5">
        <details>
          <summary className="text-label text-secondary cursor-pointer list-none">
            Full Rationale
          </summary>
          <Separator className="my-3" />
          <pre className="text-body-sm whitespace-pre-wrap break-words text-muted-foreground">
            {decision.hera_prompt}
          </pre>
        </details>
      </Card>
    </aside>
  )
}

import { Card } from "@/components/ui/card"
import { AnimatedList } from "@/components/ui/magic/animated-list"
import { TextReveal } from "@/components/ui/magic/text-reveal"
import { cn } from "@/lib/utils"

import heroDecision from "@/data/hero-decision.json"

interface OpinionCard {
  index: string
  label: string
  pick: string
  why: string
}

// Pull real fields from the actual AgentDecision the orchestrator produced.
// If we re-render with a different listing, replace src/data/hero-decision.json
// and these strings update automatically.
const decision = heroDecision as {
  hook: string
  pacing: string
  angle: string
  vibes: string
  icp?: {
    best_icp?: { persona?: string; why_it_wins?: string; emotional_driver?: string }
  }
  visual_system?: { music?: string; pacing?: string; primary_background?: string }
}

const persona = decision.icp?.best_icp?.persona ?? "—"
const whyItWins = decision.icp?.best_icp?.why_it_wins ?? ""

function trim(text: string, max: number): string {
  if (!text) return ""
  if (text.length <= max) return text
  return text.slice(0, max - 1).replace(/[,;:.\s]+\S*$/, "") + "…"
}

const CARDS: OpinionCard[] = [
  {
    index: "01",
    label: "The hook",
    pick: trim(decision.hook, 90),
    why: trim(decision.angle, 180),
  },
  {
    index: "02",
    label: "The guest",
    pick: persona,
    why: trim(whyItWins, 180),
  },
  {
    index: "03",
    label: "The pacing",
    pick: trim(decision.pacing.split(":")[0] || decision.pacing, 60),
    why: trim(decision.pacing, 200),
  },
]

export function Opinions() {
  return (
    <section
      id="opinions"
      className="relative bg-background py-24 lg:py-32"
    >
      <div className="mx-auto max-w-7xl px-6 lg:px-10">
        <div className="mb-12 max-w-2xl">
          <p className="text-label text-primary">The agent has opinions</p>
          <h2 className="mt-3 text-display-lg text-foreground sm:text-[44px]">
            What it actually <span className="italic">decided.</span>
          </h2>
          <p className="mt-4 text-base leading-relaxed text-muted-foreground">
            A snapshot from a real run on a Paris listing. Three picks the agent
            made — and why. This is the rationale rail you’ll see live during your
            own render.
          </p>
        </div>

        <div className="grid grid-cols-1 gap-5 md:grid-cols-3">
          <AnimatedList>
            {CARDS.map((card) => (
              <OpinionCardView key={card.index} card={card} />
            ))}
          </AnimatedList>
        </div>
      </div>
    </section>
  )
}

function OpinionCardView({ card }: { card: OpinionCard }) {
  return (
    <Card
      className={cn(
        "flex h-full flex-col gap-4 p-6 transition-colors hover:bg-accent/40",
      )}
    >
      <div className="flex items-center justify-between">
        <span className="font-mono text-[10px] uppercase tracking-[0.18em] text-muted-foreground">
          {card.label} · {card.index} of 03
        </span>
        <span aria-hidden className="h-1 w-1 rounded-full bg-primary" />
      </div>
      <p className="text-display-md font-display leading-tight text-foreground">
        “{card.pick}”
      </p>
      <div className="mt-auto border-l border-primary pl-3 pt-1">
        <span className="text-sm leading-relaxed text-muted-foreground">
          <TextReveal>{card.why}</TextReveal>
        </span>
      </div>
    </Card>
  )
}
